function activate(context) {
  context.ui.addToolbarButton({
    icon: 'hash',
    label: context.t('toolbar.label'),
    onClick: function () {
      var files = context.files.getAll();
      var total = 0;
      for (var i = 0; i < files.length; i++) {
        var parts = files[i].content.split(/\r?\n/);
        total += parts.length;
      }
      context.ui.showNotification(
        context.t('notify.result', { files: files.length, lines: total }),
        'info'
      );
    },
  });
}
